            }

            var player             = document.querySelector('.mainPlayerDiv'),
                playerFlvContainer   = document.querySelector('.playerFlvContainer'),
                underplayerAd        = document.querySelector('.hd'),
                relatedVideos        = document.querySelector('.js-relatedVideos'),
